const input = $input.first().json.body;

const marks = input.marks;
const markKeys = Object.keys(marks);
const avgMark = markKeys.reduce((sum, k) => sum + marks[k], 0) / markKeys.length;

const p = input.personality;
const normalizedPersonality = {
  analytical:    p.analytical     * 10,
  creative:      p.creative       * 10,
  risk_tolerance:p.risk_tolerance * 10,
  persistence:   p.persistence    * 10,
  leadership:    p.leadership     * 10
};

const interestWeights = {};
input.interests_ranked.forEach((interest, i) => {
  const w = i === 0 ? 100 : i === 1 ? 70 : 40;
  interestWeights[interest] = w;
});

return [{
  json: {
    student_name: input.name,
    class: input.class,
    stream: input.stream,
    marks: marks,
    avg_mark: Math.round(avgMark),
    personality: normalizedPersonality,
    interest_weights: interestWeights,
    financial_constraint: input.financial_constraint,
    current_skills: input.current_skills,
    goal: input.goal
  }
}];

const { student, career } = $input.first().json;

// --- SKILL FIT (25%) ---
const skillMatch = career.required_skills.filter(skill => {
  const normSkill = skill.toLowerCase();
  const hasInMarks = Object.keys(student.marks).some(m =>
    normSkill.includes(m) || m.includes(normSkill)
  );
  const hasInSkills = student.current_skills.some(s =>
    s.toLowerCase().includes(normSkill)
  );
  return hasInMarks || hasInSkills;
}).length;

const skillScore = Math.round((skillMatch / career.required_skills.length) * 100);

// --- PERSONALITY FIT (15%) ---
const pKeys = Object.keys(career.personality_fit);
const personaScore = Math.round(
  pKeys.reduce((sum, k) => {
    const studentVal = student.personality[k] || 50;
    const careerNeed = career.personality_fit[k];
    const match = 100 - Math.abs(studentVal - careerNeed);
    return sum + match;
  }, 0) / pKeys.length
);

// --- FUTURE PROOF (25%) ---
const futureScore = 100 - career.ai_automation_risk;

// --- MARKET DEMAND (20%) ---
const marketScore = career.market_demand;

// --- FEASIBILITY (15%) ---
const costMap = { low: 100, medium: 70, high: 40 };
const costScore = costMap[career.cost_band] || 50;
const timeScore = Math.max(0, 100 - (career.time_years * 10));
const feasibilityScore = Math.round((costScore + timeScore) / 2);

// --- INTEREST BOOST (10%) ---
const interestBoost = career.interest_tags.reduce((sum, tag) => {
  return sum + (student.interest_weights[tag] || 0);
}, 0) / career.interest_tags.length;

// --- FINAL SCORE ---
const finalScore = Math.round(
  skillScore       * 0.25 +
  personaScore     * 0.15 +
  futureScore      * 0.25 +
  marketScore      * 0.20 +
  feasibilityScore * 0.15 +
  interestBoost    * 0.10
);

return [{
  json: {
    career_id: career.id,
    career_title: career.title,
    final_score: finalScore,
    breakdown: {
      skill_fit: skillScore,
      personality: personaScore,
      future_proof: futureScore,
      market_demand: marketScore,
      feasibility: feasibilityScore,
      interest_boost: Math.round(interestBoost)
    },
    education_path: career.education_path,
    salary_entry: career.salary_entry,
    hybrid_tags: career.hybrid_tags,
    student_name: student.student_name
  }
}];

const all = $input.all().map(item => item.json);

// Safety check
if (all.length === 0) {
  throw new Error("No career data received");
}

// Sort descending
const sorted = all.sort((a, b) => b.final_score - a.final_score);

// Top 3 and rest
const top3 = sorted.slice(0, 3);
const avoid = sorted.slice(3);

// Hybrid tags
const allHybridTags = top3.flatMap(c => c.hybrid_tags || []);
const hybridCareer = [...new Set(allHybridTags)][0] || "AI + your top field";

// Format top 3
const top3WithReason = top3.map((c, i) => ({
  rank: i + 1,
  career_title: c.career_title,
  final_score: c.final_score,
  education_path: c.education_path,
  salary_entry: c.salary_entry,
  breakdown: c.breakdown,
  reasoning: `Ranked #${i+1} with score ${c.final_score}/100. Skill fit: ${c.breakdown?.skill_fit}/100. Personality: ${c.breakdown?.personality}/100. Future-proof: ${c.breakdown?.future_proof}/100. Market demand: ${c.breakdown?.market_demand}/100.`
}));

return [{
  json: {
    student_name: top3[0]?.student_name || "Unknown",
    top3_careers: top3WithReason,
    avoid_careers: avoid.map(c => ({
      title: c.career_title,
      score: c.final_score,
      reason: `Score ${c.final_score}/100 — low alignment with your skill set and personality profile.`
    })),
    hybrid_suggestion: hybridCareer,
    all_scores: sorted.map(c => ({
      title: c.career_title,
      score: c.final_score
    }))
  }
}];

